import React, { useEffect, useRef } from 'react';

export default function FishBackground() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx    = canvas.getContext('2d');
    let animId;

    const resize = () => {
      canvas.width  = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    resize();
    window.addEventListener('resize', resize);

    /* ── Caustic light patches ── */
    const caustics = Array.from({ length: 30 }, () => ({
      x:     Math.random() * window.innerWidth,
      y:     Math.random() * window.innerHeight * 0.85,
      rx:    30 + Math.random() * 90,
      ry:    12 + Math.random() * 40,
      rot:   Math.random() * Math.PI,
      phase: Math.random() * Math.PI * 2,
      speed: 0.005 + Math.random() * 0.011,
    }));

    /* ── Marine snow particles ── */
    const particles = Array.from({ length: 55 }, () => mkParticle());
    function mkParticle() {
      return {
        x:      Math.random() * window.innerWidth,
        y:      Math.random() * window.innerHeight,
        r:      0.5 + Math.random() * 2,
        vy:     0.07 + Math.random() * 0.2,
        vx:     (Math.random() - 0.5) * 0.2,
        alpha:  0.06 + Math.random() * 0.22,
        wobble: Math.random() * Math.PI * 2,
        wSpeed: 0.01 + Math.random() * 0.02,
      };
    }

    /* ── Bubbles ── */
    const bubbles = Array.from({ length: 20 }, () => mkBubble());
    function mkBubble() {
      return {
        x:      Math.random() * window.innerWidth,
        y:      window.innerHeight + 30,
        r:      1.5 + Math.random() * 5.5,
        speed:  0.28 + Math.random() * 0.55,
        wobble: Math.random() * Math.PI * 2,
        wSpeed: 0.013 + Math.random() * 0.022,
        alpha:  0.1 + Math.random() * 0.28,
      };
    }

    /* ── God rays ── */
    const rays = Array.from({ length: 9 }, () => ({
      x:     -200 + Math.random() * (window.innerWidth + 400),
      width: 18 + Math.random() * 50,
      phase: Math.random() * Math.PI * 2,
      speed: 0.004 + Math.random() * 0.007,
      alpha: 0.02 + Math.random() * 0.05,
      drift: (Math.random() - 0.5) * 0.12,
    }));

    const surfOff = [0, 0, 0];

    function drawWater() {
      const g = ctx.createLinearGradient(0, 0, 0, canvas.height);
      g.addColorStop(0,    'rgba(8,  68, 135, 0.6)');
      g.addColorStop(0.35, 'rgba(5,  42,  90, 0.6)');
      g.addColorStop(0.75, 'rgba(3,  22,  58, 0.65)');
      g.addColorStop(1,    'rgba(1,   9,  26, 0.72)');
      ctx.fillStyle = g;
      ctx.fillRect(0, 0, canvas.width, canvas.height);
    }

    function drawRays() {
      rays.forEach(r => {
        r.phase += r.speed;
        r.x     += r.drift;
        if (r.x > canvas.width  + 300) r.x = -300;
        if (r.x < -300)                r.x = canvas.width + 300;
        const a  = r.alpha * (0.5 + 0.5 * Math.sin(r.phase));
        const rg = ctx.createLinearGradient(r.x, 0, r.x + r.width * 2, canvas.height * 0.88);
        rg.addColorStop(0,   `rgba(170,220,255,${a})`);
        rg.addColorStop(0.6, `rgba(140,200,255,${a * 0.38})`);
        rg.addColorStop(1,   'rgba(140,200,255,0)');
        ctx.save();
        ctx.beginPath();
        ctx.moveTo(r.x,                  0);
        ctx.lineTo(r.x + r.width,        0);
        ctx.lineTo(r.x + r.width * 3.5,  canvas.height * 0.88);
        ctx.lineTo(r.x - r.width * 2.5,  canvas.height * 0.88);
        ctx.closePath();
        ctx.fillStyle = rg;
        ctx.fill();
        ctx.restore();
      });
    }

    function drawCaustics() {
      caustics.forEach(c => {
        c.phase += c.speed;
        const s = 0.5 + 0.5 * Math.abs(Math.sin(c.phase));
        const a = (0.03 + 0.07 * Math.abs(Math.sin(c.phase * 0.6)));
        ctx.save();
        ctx.globalAlpha = a;
        ctx.translate(c.x, c.y);
        ctx.rotate(c.rot + c.phase * 0.2);
        ctx.beginPath();
        ctx.ellipse(0, 0, c.rx * s, c.ry * s, 0, 0, Math.PI * 2);
        ctx.strokeStyle = 'rgba(190,235,255,0.9)';
        ctx.lineWidth   = 1.3;
        ctx.stroke();
        const ig = ctx.createRadialGradient(0, 0, 0, 0, 0, c.rx * s * 0.55);
        ig.addColorStop(0, 'rgba(215,248,255,0.16)');
        ig.addColorStop(1, 'rgba(215,248,255,0)');
        ctx.beginPath();
        ctx.ellipse(0, 0, c.rx * s * 0.55, c.ry * s * 0.55, 0, 0, Math.PI * 2);
        ctx.fillStyle = ig;
        ctx.fill();
        ctx.restore();
      });
    }

    function drawParticles() {
      particles.forEach((p, i) => {
        p.wobble += p.wSpeed;
        p.y      += p.vy;
        p.x      += p.vx + Math.sin(p.wobble) * 0.12;
        if (p.y > canvas.height + 10) particles[i] = mkParticle();
        ctx.save();
        ctx.globalAlpha = p.alpha;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(210,238,255,1)';
        ctx.fill();
        ctx.restore();
      });
    }

    function drawBubbles() {
      bubbles.forEach((b, i) => {
        b.wobble += b.wSpeed;
        b.y      -= b.speed;
        b.x      += Math.sin(b.wobble) * 0.42;
        if (b.y < -18) bubbles[i] = mkBubble();
        ctx.save();
        ctx.globalAlpha = b.alpha;
        ctx.beginPath();
        ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
        ctx.strokeStyle = 'rgba(210,245,255,0.9)';
        ctx.lineWidth   = 0.8;
        ctx.stroke();
        const bg = ctx.createRadialGradient(b.x, b.y, 0, b.x, b.y, b.r);
        bg.addColorStop(0, 'rgba(200,240,255,0.16)');
        bg.addColorStop(1, 'rgba(200,240,255,0)');
        ctx.fillStyle = bg;
        ctx.fill();
        ctx.globalAlpha = b.alpha * 1.5;
        ctx.beginPath();
        ctx.arc(b.x - b.r * 0.32, b.y - b.r * 0.32, b.r * 0.27, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.85)';
        ctx.fill();
        ctx.restore();
      });
    }

    function drawSurface() {
      for (let i = 0; i < 3; i++) {
        surfOff[i] += [0.013, 0.019, 0.008][i];
        ctx.save();
        ctx.globalAlpha = [0.1, 0.065, 0.045][i];
        ctx.beginPath();
        const yb = [25, 52, 14][i];
        ctx.moveTo(0, yb);
        for (let x = 0; x <= canvas.width; x += 8) {
          ctx.lineTo(x, yb + Math.sin(x * [0.009, 0.013, 0.007][i] + surfOff[i]) * [16, 10, 20][i]);
        }
        ctx.lineTo(canvas.width, 0);
        ctx.lineTo(0, 0);
        ctx.closePath();
        ctx.fillStyle = 'rgba(190,230,255,1)';
        ctx.fill();
        ctx.restore();
      }
    }

    function drawVignette() {
      const vg = ctx.createRadialGradient(
        canvas.width / 2, canvas.height / 2, canvas.height * 0.22,
        canvas.width / 2, canvas.height / 2, canvas.width  * 0.72,
      );
      vg.addColorStop(0, 'rgba(2,10,30,0)');
      vg.addColorStop(1, 'rgba(2,10,30,0.5)');
      ctx.fillStyle = vg;
      ctx.fillRect(0, 0, canvas.width, canvas.height);
    }

    function animate() {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      drawWater();
      drawRays();
      drawCaustics();
      drawParticles();
      drawBubbles();
      drawSurface();
      drawVignette();
      animId = requestAnimationFrame(animate);
    }
    animate();

    return () => {
      cancelAnimationFrame(animId);
      window.removeEventListener('resize', resize);
    };
  }, []);

  return (
    <>
      {/* Real underwater photo base */}
      <div style={{
        position:           'fixed',
        inset:              0,
        zIndex:             -3,
        backgroundImage:    "url('https://images.unsplash.com/photo-1518020382113-a7e8fc38eac9?auto=format&fit=crop&w=3840&q=100')",
        backgroundSize:     'cover',
        backgroundPosition: 'center',
      }} />

      {/* Water effects canvas */}
      <canvas ref={canvasRef} style={{
        position:      'fixed',
        inset:         0,
        width:         '100vw',
        height:        '100vh',
        zIndex:        -2,
        pointerEvents: 'none',
      }} />

      {/* Single Rohu fish — local generated image, transform-only animation */}
      <img
        src="/rohu_fish.png"
        alt="Rohu Fish"
        onError={e => { e.target.src = 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4a/Labeo_rohita.jpg/1280px-Labeo_rohita.jpg'; }}
        style={{
          position:      'fixed',
          zIndex:        -1,
          width:         '560px',
          maxWidth:      '50vw',
          top:           '50%',
          left:          '50%',
          pointerEvents: 'none',
          objectFit:     'contain',
          filter: [
            'drop-shadow(0 0 38px rgba(0,160,255,0.65))',
            'drop-shadow(0 14px 30px rgba(0,0,0,0.75))',
            'brightness(1.12)',
            'contrast(1.1)',
            'saturate(1.18)',
          ].join(' '),
          animation:      'rohuSwim 16s ease-in-out infinite',
          imageRendering: 'high-quality',
        }}
      />

      <style>{`
        @keyframes rohuSwim {
          0%   { transform: translate(-50%, -50%) rotate(0deg)   scaleX(1);  }
          10%  { transform: translate(-20%, -56%) rotate(-5deg)  scaleX(1);  }
          22%  { transform: translate(10%,  -44%) rotate(6deg)   scaleX(1);  }
          33%  { transform: translate(28%,  -52%) rotate(0deg)   scaleX(1);  }
          40%  { transform: translate(28%,  -52%) rotate(0deg)   scaleX(-1); }
          52%  { transform: translate(0%,   -58%) rotate(-6deg)  scaleX(-1); }
          64%  { transform: translate(-28%, -44%) rotate(5deg)   scaleX(-1); }
          74%  { transform: translate(-40%, -50%) rotate(0deg)   scaleX(-1); }
          80%  { transform: translate(-40%, -50%) rotate(0deg)   scaleX(1);  }
          90%  { transform: translate(-60%, -44%) rotate(6deg)   scaleX(1);  }
          100% { transform: translate(-50%, -50%) rotate(0deg)   scaleX(1);  }
        }
      `}</style>
    </>
  );
}
